// Phase 1: Setup Custom Fields
// Mode: runOnceForAllItems

const APOLLO_API_KEY = $('Set Config').item.json.apollo_api_key;
const BASE_URL = 'https://api.apollo.io/api/v1';

const ACCOUNT_FIELDS = [
  { label: 'Lead Score', type: 'number' },
  { label: 'Has Website', type: 'boolean' },
  { label: 'Has Online Booking', type: 'boolean' },
  { label: 'Booking Platform', type: 'string' },
  { label: 'Has Paid Ads', type: 'boolean' },
  { label: 'On Groupon', type: 'boolean' },
  { label: 'On Yelp', type: 'boolean' },
  { label: 'Google Review Count', type: 'number' },
  { label: 'Google Rating', type: 'number' },
  { label: 'Estimated Size', type: 'string' },
  { label: 'Enrichment Status', type: 'string' },
  { label: 'Category', type: 'string' },
  { label: 'VerveLabs Run Tag', type: 'string' },
  // v2: Expanded fields
  { label: 'Discovery Metro', type: 'string' },
  { label: 'Email Status', type: 'string' },
  { label: 'Phone Status', type: 'string' },
  { label: 'Phone Line Type', type: 'string' },
  { label: 'Yelp Is Claimed', type: 'boolean' },
  { label: 'Source URLs', type: 'string' },
  { label: 'Facebook URL', type: 'string' },
  { label: 'Instagram URL', type: 'string' },
  { label: 'LinkedIn URL', type: 'string' },
  { label: 'TikTok URL', type: 'string' },
  { label: 'Twitter URL', type: 'string' },
  { label: 'YouTube URL', type: 'string' },
  { label: 'Company Email', type: 'string' },
];

const CONTACT_FIELDS = [
  { label: 'Cultural Affinity', type: 'string' },
  { label: 'Is Owner', type: 'boolean' },
  { label: 'Meridian Role', type: 'string' },
  { label: 'Contact Source', type: 'string' },
  { label: 'VerveLabs Run Tag', type: 'string' },
  // v2: Expanded fields
  { label: 'Email Personal', type: 'string' },
  { label: 'Email Status', type: 'string' },
  { label: 'Email Verified At', type: 'string' },
  { label: 'Phone Status', type: 'string' },
  { label: 'Phone Verified At', type: 'string' },
  { label: 'Phone Line Type', type: 'string' },
  { label: 'Phone Carrier', type: 'string' },
  { label: 'LinkedIn URL', type: 'string' },
];

// Fetch existing custom fields
let existingFields = [];
try {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/fields`,
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': APOLLO_API_KEY,
      'Cache-Control': 'no-cache'
    },
    json: true
  });
  existingFields = data.fields || [];
} catch (e) {
  // If listing fails, proceed anyway - creates are idempotent
  console.log('Could not list existing fields:', e.message);
}

const existingLabels = new Set(
  existingFields.map(f => f.label?.toLowerCase())
);

const results = { created: [], skipped: [], errors: [] };

// Create account custom fields
for (const field of ACCOUNT_FIELDS) {
  if (existingLabels.has(field.label.toLowerCase())) {
    results.skipped.push(field.label);
    continue;
  }
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${BASE_URL}/fields`,
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': APOLLO_API_KEY
      },
      body: {
        label: field.label,
        type: field.type,
        modality: 'account'
      },
      json: true
    });
    results.created.push(field.label);
  } catch (e) {
    results.errors.push(`${field.label}: ${e.message}`);
  }
  // Rate limit: wait 700ms between calls (fires on both success and error)
  await new Promise(r => setTimeout(r, 700));
}

// Create contact custom fields
for (const field of CONTACT_FIELDS) {
  if (existingLabels.has(field.label.toLowerCase())) {
    results.skipped.push(field.label);
    continue;
  }
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `${BASE_URL}/fields`,
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': APOLLO_API_KEY
      },
      body: {
        label: field.label,
        type: field.type,
        modality: 'contact'
      },
      json: true
    });
    results.created.push(field.label);
  } catch (e) {
    results.errors.push(`${field.label}: ${e.message}`);
  }
  await new Promise(r => setTimeout(r, 700));
}

// Fetch all fields to build label-to-ID mapping for typed_custom_fields
const ACCOUNT_LABELS = new Set(ACCOUNT_FIELDS.map(f => f.label));
const CONTACT_LABELS = new Set(CONTACT_FIELDS.map(f => f.label));
const fieldMapping = { account: {}, contact: {} };
const debugFields = [];

try {
  const allFieldsData = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BASE_URL}/fields`,
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': APOLLO_API_KEY,
      'Cache-Control': 'no-cache'
    },
    json: true
  });
  const allFields = allFieldsData.fields || [];
  const getRawId = (val) => val ? val.split('.').pop() : val;
  for (const f of allFields) {
    if (ACCOUNT_LABELS.has(f.label) || CONTACT_LABELS.has(f.label)) {
      debugFields.push({ label: f.label, id: f.id, key: f.key, modality: f.modality });
    }
    if (f.modality === 'account' && ACCOUNT_LABELS.has(f.label)) {
      fieldMapping.account[f.label] = getRawId(f.id) || getRawId(f.key);
    }
    if (f.modality === 'contact' && CONTACT_LABELS.has(f.label)) {
      fieldMapping.contact[f.label] = getRawId(f.id) || getRawId(f.key);
    }
  }
} catch (e) {
  results.errors.push(`Field mapping fetch failed: ${e.message}`);
}

return [{
  json: {
    phase: 'custom_fields_setup',
    ...results,
    field_mapping: fieldMapping,
    _debug_fields: debugFields
  }
}];

// Phase 2: Fetch Unsynced Data from Supabase
// Mode: runOnceForAllItems

const SUPABASE_URL = $('Set Config').item.json.supabase_url;
const SUPABASE_KEY = $('Set Config').item.json.supabase_service_key;
const RUN_TAG = $('Set Config').item.json.run_tag;

const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

// Fetch companies needing sync (with social_profiles embedded)
let companies;
try {
  companies = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/companies?enrichment_status=eq.fully_enriched&apollo_synced_at=is.null&select=*,social_profiles(platform,profile_url)&order=city,name&limit=50`,
    headers,
    json: true
  });
} catch (e) {
  return [{ json: { phase: 'fetch', error: `Fetch companies failed: ${e.message}`, companies: [] } }];
}

if (!companies || companies.length === 0) {
  return [{ json: { phase: 'fetch', companies: [], message: 'No unsynced companies found' } }];
}

// Flatten social_profiles into company-level URL fields
for (const company of companies) {
  company.facebook_url = null;
  company.instagram_url = null;
  company.linkedin_url = null;
  company.tiktok_url = null;
  company.twitter_url = null;
  company.youtube_url = null;
  if (company.social_profiles && Array.isArray(company.social_profiles)) {
    for (const profile of company.social_profiles) {
      const p = profile.platform?.toLowerCase();
      if (p === 'facebook') company.facebook_url = profile.profile_url;
      else if (p === 'instagram') company.instagram_url = profile.profile_url;
      else if (p === 'linkedin') company.linkedin_url = profile.profile_url;
      else if (p === 'tiktok') company.tiktok_url = profile.profile_url;
      else if (p === 'x' || p === 'twitter') company.twitter_url = profile.profile_url;
      else if (p === 'youtube') company.youtube_url = profile.profile_url;
    }
    delete company.social_profiles;
  }
}

// Fetch contacts for these companies
const companyIds = companies.map(c => c.id);
let contacts;
try {
  contacts = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/contacts?company_id=in.(${companyIds.join(',')})&select=*`,
    headers,
    json: true
  });
} catch (e) {
  return [{ json: { phase: 'fetch', error: `Fetch contacts failed: ${e.message}`, companies: [] } }];
}

// Group contacts by company_id
const contactsByCompany = {};
for (const contact of contacts) {
  if (!contactsByCompany[contact.company_id]) {
    contactsByCompany[contact.company_id] = [];
  }
  contactsByCompany[contact.company_id].push(contact);
}

// Get field mapping from upstream Setup Custom Fields node
const fieldMapping = $('Setup Custom Fields').first().json.field_mapping || { account: {}, contact: {} };

// Emit one item per company with its contacts attached
return companies.map(company => {
  let companyContacts = contactsByCompany[company.id] || [];

  // Inject synthetic 'Front Desk' contact for companies with no contacts
  // so Orum dialer can reach them via their main phone number
  if (companyContacts.length === 0) {
    companyContacts = [{
      id: `synthetic-${company.id}`,
      first_name: 'Front Desk',
      last_name: company.name || 'Main Line',
      phone_direct: company.phone || '',
      role: 'Gatekeeper',
      is_owner: false,
      source: 'synthetic_fallback',
      email_business: company.email || '',
      cultural_affinity: '',
      email_personal: '',
      phone_carrier: '',
      email_status: company.email_status || '',
      phone_status: company.phone_status || '',
      phone_line_type: company.phone_line_type || '',
      company_id: company.id
    }];
  }

  return {
    json: {
      company,
      contacts: companyContacts,
      run_tag: RUN_TAG,
      field_mapping: fieldMapping
    }
  };
});

// Filter to only items with valid company data
const items = $input.all();
const valid = items.filter(i => i.json.company && i.json.company.id);
if (valid.length === 0) return [];
return valid.map(i => ({ json: i.json }));

// Phase 3: Upsert Account in Apollo
// Mode: runOnceForEachItem
// v2: Immediate Supabase save + name-based account search fallback

const APOLLO_API_KEY = $('Set Config').item.json.apollo_api_key;
const SUPABASE_URL = $('Set Config').item.json.supabase_url;
const SUPABASE_KEY = $('Set Config').item.json.supabase_service_key;
const BASE_URL = 'https://api.apollo.io/api/v1';
const company = $input.item.json.company;
const contacts = $input.item.json.contacts;
const run_tag = $input.item.json.run_tag;
const fieldMapping = $input.item.json.field_mapping || { account: {}, contact: {} };

const apiHeaders = {
  'Content-Type': 'application/json',
  'x-api-key': APOLLO_API_KEY,
  'Cache-Control': 'no-cache'
};

const supabaseHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

// Platform/social domains - skip domain search (would match wrong accounts)
const SKIP_DOMAINS = new Set([
  'facebook.com', 'instagram.com', 'twitter.com', 'linkedin.com',
  'youtube.com', 'tiktok.com', 'yelp.com', 'nextdoor.com',
  'wixsite.com', 'wix.com', 'square.site', 'squarespace.com',
  'setmore.com', 'schedulista.com', 'glossgenius.com',
  'genbook.com', 'jane.app', 'acuityscheduling.com',
  'mindbodyonline.com', 'mindbody.io', 'vagaro.com',
  'fresha.com', 'schedulicity.com', 'booksy.com',
  'massagebook.com', 'noterro.com', 'clinicsense.com', 'calendly.com'
]);

// Build typed_custom_fields using field IDs from mapping
// Truthy-only for strings/numbers to avoid overwriting manual Apollo edits
// != null for booleans since false is a valid value we want to push
const fm = fieldMapping.account;
const typedCustomFields = {};
// Existing fields — upgraded to truthy-only
if (fm['Lead Score'] && company.lead_score) typedCustomFields[fm['Lead Score']] = company.lead_score;
if (fm['Has Website'] && company.has_website != null) typedCustomFields[fm['Has Website']] = company.has_website;
if (fm['Has Online Booking'] && company.has_online_booking != null) typedCustomFields[fm['Has Online Booking']] = company.has_online_booking;
if (fm['Booking Platform'] && company.booking_platform) typedCustomFields[fm['Booking Platform']] = company.booking_platform;
if (fm['Has Paid Ads'] && company.has_paid_ads != null) typedCustomFields[fm['Has Paid Ads']] = company.has_paid_ads;
if (fm['On Groupon'] && company.on_groupon != null) typedCustomFields[fm['On Groupon']] = company.on_groupon;
if (fm['On Yelp'] && company.on_yelp != null) typedCustomFields[fm['On Yelp']] = company.on_yelp;
if (fm['Google Review Count'] && company.google_review_count) typedCustomFields[fm['Google Review Count']] = company.google_review_count;
if (fm['Google Rating'] && company.google_rating) typedCustomFields[fm['Google Rating']] = parseFloat(company.google_rating);
if (fm['Estimated Size'] && company.estimated_size) typedCustomFields[fm['Estimated Size']] = company.estimated_size;
if (fm['Enrichment Status'] && company.enrichment_status) typedCustomFields[fm['Enrichment Status']] = company.enrichment_status;
if (fm['Category'] && company.category) typedCustomFields[fm['Category']] = company.category;
if (fm['VerveLabs Run Tag']) typedCustomFields[fm['VerveLabs Run Tag']] = run_tag;
// v2: New core fields
if (fm['Discovery Metro'] && company.discovery_metro) typedCustomFields[fm['Discovery Metro']] = company.discovery_metro;
if (fm['Email Status'] && company.email_status) typedCustomFields[fm['Email Status']] = company.email_status;
if (fm['Phone Status'] && company.phone_status) typedCustomFields[fm['Phone Status']] = company.phone_status;
if (fm['Phone Line Type'] && company.phone_line_type) typedCustomFields[fm['Phone Line Type']] = company.phone_line_type;
if (fm['Yelp Is Claimed'] && company.yelp_is_claimed != null) typedCustomFields[fm['Yelp Is Claimed']] = company.yelp_is_claimed;
if (fm['Source URLs'] && company.source_urls) typedCustomFields[fm['Source URLs']] = JSON.stringify(company.source_urls);
// v2: Social URLs (flattened from social_profiles in Fetch Unsynced)
if (fm['Facebook URL'] && company.facebook_url) typedCustomFields[fm['Facebook URL']] = company.facebook_url;
if (fm['Instagram URL'] && company.instagram_url) typedCustomFields[fm['Instagram URL']] = company.instagram_url;
if (fm['LinkedIn URL'] && company.linkedin_url) typedCustomFields[fm['LinkedIn URL']] = company.linkedin_url;
if (fm['TikTok URL'] && company.tiktok_url) typedCustomFields[fm['TikTok URL']] = company.tiktok_url;
if (fm['Twitter URL'] && company.twitter_url) typedCustomFields[fm['Twitter URL']] = company.twitter_url;
if (fm['YouTube URL'] && company.youtube_url) typedCustomFields[fm['YouTube URL']] = company.youtube_url;
if (fm['Company Email'] && company.email) typedCustomFields[fm['Company Email']] = company.email;

let apolloAccountId = company.apollo_account_id;
let action = 'skipped';
const isSkipDomain = company.domain && SKIP_DOMAINS.has(company.domain);

try {
  // Step 1a: Search for existing account by domain (skip platform domains)
  if (company.domain && !isSkipDomain && !apolloAccountId) {
    try {
      const searchData = await this.helpers.httpRequest({
        method: 'POST',
        url: `${BASE_URL}/accounts/search`,
        headers: apiHeaders,
        body: {
          q_organization_domains: company.domain,
          page: 1,
          per_page: 1
        },
        json: true
      });
      if (searchData.accounts && searchData.accounts.length > 0) {
        apolloAccountId = searchData.accounts[0].id;
      }
    } catch (e) {
      console.log(`Domain search failed for ${company.domain}: ${e.message}`);
    }
    await new Promise(r => setTimeout(r, 700));
  }

  // Step 1b: Fallback — search by company name if domain search was skipped or found nothing
  if (!apolloAccountId) {
    try {
      const nameSearchData = await this.helpers.httpRequest({
        method: 'POST',
        url: `${BASE_URL}/accounts/search`,
        headers: apiHeaders,
        body: {
          q_organization_name: company.name,
          page: 1,
          per_page: 5
        },
        json: true
      });
      if (nameSearchData.accounts && nameSearchData.accounts.length > 0) {
        const exactMatch = nameSearchData.accounts.find(
          a => a.name?.toLowerCase() === company.name?.toLowerCase()
        );
        if (exactMatch) {
          apolloAccountId = exactMatch.id;
        }
      }
    } catch (e) {
      console.log(`Name search failed for ${company.name}: ${e.message}`);
    }
    await new Promise(r => setTimeout(r, 700));
  }

  // Step 2: Build account payload (API-compliant params only)
  const rawAddr = company.address || [company.city, company.state, company.country || 'US'].filter(Boolean).join(', ');
  const accountPayload = {
    name: company.name,
    domain: (!isSkipDomain && company.domain)
      ? company.domain.replace(/^(?:https?:\/\/)?(?:www\.)?/i, '').split('/')[0]
      : undefined,
    phone: company.phone || undefined,
    raw_address: rawAddr || undefined,
    typed_custom_fields: typedCustomFields
  };

  // Step 3: Update or Create
  if (apolloAccountId) {
    // UPDATE existing account
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${BASE_URL}/accounts/${apolloAccountId}`,
        headers: apiHeaders,
        body: accountPayload,
        json: true
      });
      action = 'updated';
      // Immediately save to Supabase
      try {
        await this.helpers.httpRequest({
          method: 'PATCH',
          url: `${SUPABASE_URL}/rest/v1/companies?id=eq.${company.id}`,
          headers: supabaseHeaders,
          body: {
            apollo_account_id: apolloAccountId,
            apollo_synced_at: new Date().toISOString()
          },
          json: true
        });
      } catch (e) {
        console.log(`Immediate Supabase save failed for ${company.id}: ${e.message}`);
      }
    } catch (e) {
      action = `update_error: ${e.message}`;
    }
  } else {
    // CREATE new account
    try {
      const createData = await this.helpers.httpRequest({
        method: 'POST',
        url: `${BASE_URL}/accounts`,
        headers: apiHeaders,
        body: accountPayload,
        json: true
      });
      if (createData.account) {
        apolloAccountId = createData.account.id;
        action = 'created';
        // Immediately save to Supabase so this company is never re-fetched
        try {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: `${SUPABASE_URL}/rest/v1/companies?id=eq.${company.id}`,
            headers: supabaseHeaders,
            body: {
              apollo_account_id: apolloAccountId,
              apollo_synced_at: new Date().toISOString()
            },
            json: true
          });
        } catch (e) {
          console.log(`Immediate Supabase save failed for ${company.id}: ${e.message}`);
        }
      } else {
        action = 'create_error: no account in response';
      }
    } catch (e) {
      action = `create_error: ${e.message}`;
    }
  }

  // Rate limit pause
  await new Promise(r => setTimeout(r, 700));

} catch (e) {
  action = `exception: ${e.message}`;
}

return {
  json: {
    company,
    contacts,
    run_tag,
    apollo_account_id: apolloAccountId,
    account_action: action,
    _config: {
      apollo_api_key: APOLLO_API_KEY,
      supabase_url: SUPABASE_URL,
      supabase_service_key: SUPABASE_KEY,
      field_mapping: fieldMapping
    }
  }
};

// Phase 4: Upsert Contacts in Apollo
// Mode: runOnceForEachItem
// v2: Immediate Supabase save after each contact create/update

const config = $input.item.json._config;
const APOLLO_API_KEY = config.apollo_api_key;
const BASE_URL = 'https://api.apollo.io/api/v1';
const company = $input.item.json.company;
const contacts = $input.item.json.contacts;
const run_tag = $input.item.json.run_tag;
const apolloAccountId = $input.item.json.apollo_account_id;
const fieldMapping = config.field_mapping || { account: {}, contact: {} };

const apiHeaders = {
  'Content-Type': 'application/json',
  'x-api-key': APOLLO_API_KEY,
  'Cache-Control': 'no-cache'
};

const supabaseHeaders = {
  'apikey': config.supabase_service_key,
  'Authorization': `Bearer ${config.supabase_service_key}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const contactResults = [];

for (const contact of contacts) {
  try {
    let apolloContactId = contact.apollo_contact_id;
    let action = 'skipped';

    // Build typed_custom_fields using field IDs from mapping
    // Truthy-only for strings to avoid overwriting manual Apollo edits
    // != null for booleans since false is a valid value
    const cfm = fieldMapping.contact;
    const typedContactFields = {};
    // Existing fields — upgraded to truthy-only
    if (cfm['Cultural Affinity'] && contact.cultural_affinity) typedContactFields[cfm['Cultural Affinity']] = contact.cultural_affinity;
    if (cfm['Is Owner'] && contact.is_owner != null) typedContactFields[cfm['Is Owner']] = contact.is_owner;
    if (cfm['Meridian Role'] && contact.role) typedContactFields[cfm['Meridian Role']] = contact.role;
    if (cfm['Contact Source'] && contact.source) typedContactFields[cfm['Contact Source']] = contact.source;
    if (cfm['VerveLabs Run Tag']) typedContactFields[cfm['VerveLabs Run Tag']] = run_tag;
    // v2: New fields
    if (cfm['Email Personal'] && contact.email_personal) typedContactFields[cfm['Email Personal']] = contact.email_personal;
    if (cfm['Email Status'] && contact.email_status) typedContactFields[cfm['Email Status']] = contact.email_status;
    if (cfm['Email Verified At'] && contact.email_verified_at) typedContactFields[cfm['Email Verified At']] = contact.email_verified_at;
    if (cfm['Phone Status'] && contact.phone_status) typedContactFields[cfm['Phone Status']] = contact.phone_status;
    if (cfm['Phone Verified At'] && contact.phone_verified_at) typedContactFields[cfm['Phone Verified At']] = contact.phone_verified_at;
    if (cfm['Phone Line Type'] && contact.phone_line_type) typedContactFields[cfm['Phone Line Type']] = contact.phone_line_type;
    if (cfm['Phone Carrier'] && contact.phone_carrier) typedContactFields[cfm['Phone Carrier']] = contact.phone_carrier;
    if (cfm['LinkedIn URL'] && contact.linkedin_url) typedContactFields[cfm['LinkedIn URL']] = contact.linkedin_url;

    const contactPayload = {
      first_name: contact.first_name || '',
      last_name: contact.last_name || '',
      organization_name: company.name,
      account_id: apolloAccountId || undefined,
      title: contact.role === 'owner' ? 'Owner'
        : contact.role === 'manager' ? 'Manager'
        : contact.role === 'practitioner'
          ? 'Practitioner' : undefined,
      email: contact.email_business
        || contact.email_personal || undefined,
      direct_phone: contact.phone_direct || undefined,
      corporate_phone: company.phone || undefined,
      present_raw_address: contact.location
        || company.address || undefined,
      typed_custom_fields: typedContactFields
    };

    if (apolloContactId) {
      // UPDATE existing contact
      try {
        await this.helpers.httpRequest({
          method: 'PATCH',
          url: `${BASE_URL}/contacts/${apolloContactId}`,
          headers: apiHeaders,
          body: contactPayload,
          json: true
        });
        action = 'updated';
        // Immediately save to Supabase
        try {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: `${config.supabase_url}/rest/v1/contacts?id=eq.${contact.id}`,
            headers: supabaseHeaders,
            body: {
              apollo_contact_id: apolloContactId,
              apollo_synced_at: new Date().toISOString()
            },
            json: true
          });
        } catch (e) {
          console.log(`Immediate contact save failed for ${contact.id}: ${e.message}`);
        }
      } catch (e) {
        action = `update_error: ${e.message}`;
      }
    } else {
      // CREATE with dedup enabled + label tagging
      contactPayload.run_dedupe = true;
      contactPayload.label_names = [run_tag];
      try {
        const createData = await this.helpers.httpRequest({
          method: 'POST',
          url: `${BASE_URL}/contacts`,
          headers: apiHeaders,
          body: contactPayload,
          json: true
        });
        if (createData.contact) {
          apolloContactId = createData.contact.id;
          action = 'created';
          // Immediately save to Supabase
          try {
            await this.helpers.httpRequest({
              method: 'PATCH',
              url: `${config.supabase_url}/rest/v1/contacts?id=eq.${contact.id}`,
              headers: supabaseHeaders,
              body: {
                apollo_contact_id: apolloContactId,
                apollo_synced_at: new Date().toISOString()
              },
              json: true
            });
          } catch (e) {
            console.log(`Immediate contact save failed for ${contact.id}: ${e.message}`);
          }
        } else {
          action = 'create_error: no contact in response';
        }
      } catch (e) {
        action = `create_error: ${e.message}`;
      }
    }

    contactResults.push({
      supabase_contact_id: contact.id,
      apollo_contact_id: apolloContactId,
      name: `${contact.first_name} ${contact.last_name}`,
      action
    });

    // Rate limit: 700ms between API calls
    await new Promise(r => setTimeout(r, 700));

  } catch (e) {
    contactResults.push({
      supabase_contact_id: contact.id,
      name: `${contact.first_name} ${contact.last_name}`,
      action: `exception: ${e.message}`
    });
  }
}

return {
  json: {
    company_id: company.id,
    company_name: company.name,
    apollo_account_id: apolloAccountId,
    account_action: $input.item.json.account_action,
    contact_results: contactResults,
    _config: config
  }
};

// Phase 5: Mark Synced in Supabase
// Mode: runOnceForEachItem

const config = $input.item.json._config;
const SUPABASE_URL = config.supabase_url;
const SUPABASE_KEY = config.supabase_service_key;
const item = $input.item.json;
const now = new Date().toISOString();

const headers = {
  'apikey': SUPABASE_KEY,
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const results = { company: null, contacts: [] };

try {
  // Update company apollo_account_id + apollo_synced_at
  if (item.apollo_account_id) {
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: `${SUPABASE_URL}/rest/v1/companies?id=eq.${item.company_id}`,
        headers,
        body: {
          apollo_account_id: item.apollo_account_id,
          apollo_synced_at: now
        },
        json: true
      });
      results.company = 'synced';
    } catch (e) {
      results.company = `error: ${e.message}`;
    }
  }

  // Update each contact's apollo_contact_id + apollo_synced_at
  for (const cr of (item.contact_results || [])) {
    if (cr.apollo_contact_id && cr.supabase_contact_id) {
      try {
        await this.helpers.httpRequest({
          method: 'PATCH',
          url: `${SUPABASE_URL}/rest/v1/contacts?id=eq.${cr.supabase_contact_id}`,
          headers,
          body: {
            apollo_contact_id: cr.apollo_contact_id,
            apollo_synced_at: now
          },
          json: true
        });
        results.contacts.push({
          id: cr.supabase_contact_id,
          status: 'synced'
        });
      } catch (e) {
        results.contacts.push({
          id: cr.supabase_contact_id,
          status: `error: ${e.message}`
        });
      }
    }
  }
} catch (e) {
  results.error = e.message;
}

return {
  json: {
    company_id: item.company_id,
    company_name: item.company_name,
    apollo_account_id: item.apollo_account_id,
    account_action: item.account_action,
    contact_results: item.contact_results,
    sync_results: results
  }
};

// Log Summary — aggregate sync results from all batches
// Mode: runOnceForAllItems
// Receives all items from the SplitInBatches "done" output,
// which aggregates every item that passed through the loop.

const items = $input.all();
const summary = {
  accounts_created: 0,
  accounts_updated: 0,
  accounts_error: 0,
  contacts_created: 0,
  contacts_updated: 0,
  contacts_error: 0,
  companies_synced: 0
};

for (const item of items) {
  const d = item.json;

  // Count company sync results
  if (d.sync_results?.company === 'synced') summary.companies_synced++;

  // Count account actions
  if (d.account_action === 'created') summary.accounts_created++;
  else if (d.account_action === 'updated') summary.accounts_updated++;
  else if (d.account_action?.includes('error')) summary.accounts_error++;

  // Count contact results
  for (const cr of (d.contact_results || [])) {
    if (cr.action === 'created') summary.contacts_created++;
    else if (cr.action === 'updated') summary.contacts_updated++;
    else if (cr.action?.includes('error')) summary.contacts_error++;
  }
}

summary.total_items = items.length;
console.log('Apollo Sync Summary:', JSON.stringify(summary));
return [{ json: summary }];
